package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.InputType
import android.widget.Button
import android.widget.EditText
import android.widget.LinearLayout
import android.widget.TextView
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat
import androidx.core.view.setPadding

object AuthPrefs {
    private const val PREFS = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    fun prefs(context: Context): SharedPreferences =
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clear(context: Context) {
        prefs(context).edit().clear().apply()
    }
}

class LauncherActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, HomeActivity::class.java))
        } else {
            startActivity(Intent(this, LoginActivity::class.java))
        }
        finish()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var statusText: TextView
    private lateinit var biometricButton: Button
    private lateinit var passwordButton: Button

    private val enrollmentLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) {
        tryAuthenticateWithBiometrics()
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        val root = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(dp(20))
        }

        statusText = TextView(this).apply {
            text = "Sign in"
            textSize = 18f
        }

        biometricButton = Button(this).apply {
            text = "Use fingerprint"
            setOnClickListener { tryAuthenticateWithBiometrics() }
        }

        passwordButton = Button(this).apply {
            text = "Use password"
            setOnClickListener { showPasswordDialog() }
        }

        root.addView(statusText)
        root.addView(space())
        root.addView(biometricButton)
        root.addView(space())
        root.addView(passwordButton)

        setContentView(root)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        tryAuthenticateWithBiometrics(auto = true)
    }

    private fun tryAuthenticateWithBiometrics(auto: Boolean = false) {
        val biometricManager = BiometricManager.from(this)
        val canAuth = biometricManager.canAuthenticate(
            BiometricManager.Authenticators.BIOMETRIC_STRONG or
                BiometricManager.Authenticators.BIOMETRIC_WEAK
        )

        when (canAuth) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricButton.isEnabled = true
                statusText.text = if (auto) "Authenticating with fingerprint…" else "Ready for fingerprint"
                showBiometricPrompt()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                biometricButton.isEnabled = false
                statusText.text = "No fingerprint enrolled. Use password or enroll a fingerprint."
                showEnrollDialog()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE,
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                biometricButton.isEnabled = false
                statusText.text = "Fingerprint not available on this device. Use password."
                if (auto) showPasswordDialog()
            }
            else -> {
                biometricButton.isEnabled = false
                statusText.text = "Fingerprint unavailable. Use password."
                if (auto) showPasswordDialog()
            }
        }
    }

    private fun showEnrollDialog() {
        AlertDialog.Builder(this)
            .setTitle("Set up fingerprint")
            .setMessage("To use fingerprint sign-in, enroll a fingerprint in device settings.")
            .setPositiveButton("Open settings") { _, _ ->
                val intent = Intent(android.provider.Settings.ACTION_BIOMETRIC_ENROLL).apply {
                    putExtra(
                        android.provider.Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                        BiometricManager.Authenticators.BIOMETRIC_STRONG or
                            BiometricManager.Authenticators.BIOMETRIC_WEAK
                    )
                }
                enrollmentLauncher.launch(intent)
            }
            .setNegativeButton("Use password") { _, _ -> showPasswordDialog() }
            .show()
    }

    private fun showBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        val prompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    AuthPrefs.setAuthenticated(this@LoginActivity, true)
                    goHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    statusText.text = errString.toString()
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON ||
                        errorCode == BiometricPrompt.ERROR_USER_CANCELED ||
                        errorCode == BiometricPrompt.ERROR_CANCELED
                    ) {
                        showPasswordDialog()
                    }
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusText.text = "Fingerprint not recognized. Try again or use password."
                }
            }
        )

        val info = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint sign-in")
            .setSubtitle("Confirm your identity")
            .setDescription("Use your fingerprint to sign in quickly.")
            .setNegativeButtonText("Use password")
            .build()

        prompt.authenticate(info)
    }

    private fun showPasswordDialog() {
        val input = EditText(this).apply {
            hint = "Password"
            inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD
        }

        AlertDialog.Builder(this)
            .setTitle("Password sign-in")
            .setMessage("Enter your password to continue.")
            .setView(input)
            .setPositiveButton("Sign in") { _, _ ->
                val password = input.text?.toString().orEmpty()
                if (validatePassword(password)) {
                    AuthPrefs.setAuthenticated(this, true)
                    goHome()
                } else {
                    statusText.text = "Incorrect password. Try again."
                    showPasswordDialog()
                }
            }
            .setNegativeButton("Cancel", null)
            .show()
    }

    private fun validatePassword(password: String): Boolean {
        return password == "password123"
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }

    private fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

    private fun space(): TextView = TextView(this).apply { text = " " }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        if (!AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        val root = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            setPadding(dp(20))
        }

        val title = TextView(this).apply {
            text = "Home"
            textSize = 20f
        }

        val subtitle = TextView(this).apply {
            text = "You are signed in."
            textSize = 16f
        }

        val logout = Button(this).apply {
            text = "Log out"
            setOnClickListener {
                AuthPrefs.setAuthenticated(this@HomeActivity, false)
                startActivity(Intent(this@HomeActivity, LoginActivity::class.java))
                finish()
            }
        }

        root.addView(title)
        root.addView(space())
        root.addView(subtitle)
        root.addView(space())
        root.addView(logout)

        setContentView(root)
    }

    private fun dp(value: Int): Int = (value * resources.displayMetrics.density).toInt()

    private fun space(): TextView = TextView(this).apply { text = " " }
}